import { createClient } from "@supabase/supabase-js"

const supabaseUrl = import.meta.env.VITE_SUPABASE_URL || "https://placeholder.supabase.co"
const supabaseKey = import.meta.env.VITE_SUPABASE_ANON_KEY || "placeholder"
export const supabase = createClient(supabaseUrl, supabaseKey)

const LOCAL_KEY = "gto_platform_v1"

function getLocal() {
  try {
    const d = localStorage.getItem(LOCAL_KEY)
    if (!d) return getDefaults()
    const parsed = JSON.parse(d)
    // Migratie: voeg standaard_voorwaarden toe als die nog niet aanwezig zijn
    if (!parsed.standaard_voorwaarden) {
      const defaults = getDefaults()
      parsed.standaard_voorwaarden = defaults.standaard_voorwaarden
      localStorage.setItem(LOCAL_KEY, JSON.stringify(parsed))
    }
    return parsed
  } catch { return getDefaults() }
}

function setLocal(data) {
  try { localStorage.setItem(LOCAL_KEY, JSON.stringify(data)) } catch {}
}

